-- 初始化脏器标签（59条）

-- 同步数据到脏器表

-- 插入tb_organ中不存在于tb_structure_tag_set的记录
SELECT a.name, a.name_en, a.species_id, a.organ_code, a.organization_id, 1, 1
FROM tb_organ a
WHERE a.species_id = '3' AND a.organization_id = 1;

-- 结构初始化

-- 结构标签初始化
                                                                                                                                   b.structure_tag_set_id,
                                                                                                                                   CONCAT( c.NAME, b.structure_tag_set_name, a.`name` ),
                                                                                                                                   a.structure_id,
                                                                                                                                   a.organization_id,
                                                                                                                                   1,
                                                                                                                                   1
FROM
    tb_structure a
        LEFT JOIN tb_structure_tag_set b ON a.species_id = b.species_id
        AND a.organ_code = b.organ_code
        AND a.organization_id = b.organization_id
        LEFT JOIN tb_species c ON b.species_id = c.species_id
        AND b.organization_id = c.organization_id
WHERE
    a.species_id = '3';

